        //                     "settlementFeeRate" => null,
        //                     "maxLeverage" => 125,
        //                     "indexSourceExchanges" => ["okex","binance","kucoin","bybit","bitmart","gateio"],
        //                     "k" => "490.0",
        //                     "m" => "300.0",
        //                     "f" => "1.3",
