            //                 }
            //             )
            //         }
            //     }
            //
        }
        $data = $this->safe_dict($response, 'data', array());
        $tickers = $this->safe_list_2($data, 'ticker', 'list', array());
        $time = $this->safe_integer_2($data, 'time', 'ts');
        $result = array();
        for ($i = 0; $i < count($tickers); $i++) {
