            //
            //     {
            //         "code" => "200000",
            //         "data" => array(
            //             array(
            //                 "address" => "fr1qvus7d4d5fgxj5e7zvqe6yhxd7txm95h2and69r",
            //                 "memo" => "",
            //                 "chain" => "BTC-Segwit",
