        //         "data" => {
        //             "totalConversionBalance" => "0.02138647",
        //             "liabilityConversionBalance" => "0.01480001",
        //             "assets" => array(
        //                 {
        //                     "symbol" => "MANA-USDT",
        //                     "debtRatio" => "0",
        //                     "status" => "BORROW",
        //                     "baseAsset" => array(
        //                         "currency" => "MANA",
        //                         "borrowEnabled" => true,
        //                         "repayEnabled" => true,
        //                         "transferEnabled" => true,
        //                         "borrowed" => "0",
