        $currency = $this->currency($code);
        $request = array(
            'currency' => $currency['id'],
            'size' => $this->currency_to_precision($code, $amount),
            'timeInForce' => 'FOK',
        );
        $response = $this->privatePostMarginBorrow ($this->extend($request, $params));
